mapper.sql:
WITH matched_products AS ( SELECT /*+ MATERIALIZE */ p.id FROM products p WHERE
CONTAINS(p.name, #{keywordLike}) > 0
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
AND EXISTS ( SELECT 1 FROM hot_deals h JOIN hot_deal_products hp ON hp.hot_deal_id = h.id JOIN product_options po ON po.id = hp.product_option_id WHERE po.product_id = p.id AND h.deleted_at IS NULL AND SYSTIMESTAMP BETWEEN h.starts_at AND h.ends_at AND FLOOR((hp.original_price - hp.hot_deal_price) / hp.original_price * 100) >= #{minDiscountRate} )
)
